# =============================================================================
# Security: Validate directory permissions
# =============================================================================
sub validate_directory_permissions {
    my ($dir) = @_;

    unless (-d $dir) {
        croak "Plugin directory does not exist: $dir";
    }

    my @stat = stat($dir);
    my $mode = $stat[2] & 07777;

    # Directory should be owned by root or current user, not world-writable
    if ($mode & 002) {
        croak "Plugin directory is world-writable (insecure): $dir";
    }

    my $dir_uid = $stat[4];
    my $my_uid  = $<;
    if ($dir_uid != 0 && $dir_uid != $my_uid) {
        croak "Plugin directory is not owned by root or current user: $dir";
    }

    return 1;
}

# =============================================================================
# Security: Validate file permissions
# =============================================================================
sub validate_file_permissions {
    my ($filepath) = @_;

    unless (-f $filepath) {
        croak "Plugin file does not exist: $filepath";
    }

    my @stat = stat($filepath);
    my $mode = $stat[2] & 07777;

    # File should not be world-writable
    if ($mode & 002) {
        croak "Plugin file is world-writable (insecure): $filepath";
    }

    # File should not be writable by group
    if ($mode & 020) {
        warn "Warning: Plugin file is group-writable: $filepath\n";
    }

    return 1;
}

# =============================================================================
# Security: Load trusted checksums from manifest
# =============================================================================
sub load_manifest {
    my ($manifest_path) = @_;

    unless (-f $manifest_path) {
        croak "Plugin manifest file not found: $manifest_path";
    }

    validate_file_permissions($manifest_path);

    my %checksums;
    open my $fh, '<', $manifest_path
        or croak "Cannot open manifest: $manifest_path: $!";

    while (my $line = <$fh>) {
        chomp $line;
        next if $line =~ /^\s*#/;   # skip comments
        next if $line =~ /^\s*$/;   # skip blank lines

        if ($line =~ /^([a-f0-9]{64})\s+(\S+)$/) {
            my ($checksum, $plugin_name) = ($1, $2);
            # Validate plugin name contains only safe characters
            if ($plugin_name =~ /\A[a-zA-Z0-9_\-]+\.pl\z/) {
                $checksums{$plugin_name} = $checksum;
            } else {
                warn "Skipping invalid plugin name in manifest: $plugin_name\n";
            }
        } else {
            warn "Skipping malformed manifest line: $line\n";
        }
    }
    close $fh;

    return \%checksums;
}

# =============================================================================
# Security: Verify file integrity via SHA-256 checksum
# =============================================================================
sub verify_checksum {
    my ($filepath, $expected_checksum) = @_;

    open my $fh, '<', $filepath
        or croak "Cannot open file for checksum: $filepath: $!";
    my $content = do { local $/; <$fh> };
    close $fh;

    my $actual_checksum = sha256_hex($content);

    if ($actual_checksum ne $expected_checksum) {
        croak "Checksum mismatch for $filepath\n"
            . "  Expected: $expected_checksum\n"
            . "  Actual:   $actual_checksum\n"
            . "  Plugin may have been tampered with!";
    }

    return 1;
}

# =============================================================================
# Security: Validate plugin name (path traversal prevention)
# =============================================================================
sub validate_plugin_name {
    my ($name) = @_;

    # Only allow alphanumeric, underscore, hyphen, ending in .pl
    unless ($name =~ /\A[a-zA-Z0-9_\-]+\.pl\z/) {
        croak "Invalid plugin name (must match [a-zA-Z0-9_-]+.pl): $name";
    }

    # Extra safety: no path separators
    if ($name =~ m{[/\\]}) {
        croak "Plugin name contains path separators: $name";
    }

    return 1;
}

# =============================================================================
# Security: Scan plugin code for dangerous operations
# =============================================================================
sub scan_plugin_code {
    my ($filepath) = @_;

    my $size = -s $filepath;
    if ($size > $MAX_PLUGIN_SIZE) {
        croak "Plugin file exceeds maximum size ($MAX_PLUGIN_SIZE bytes): $filepath";
    }

    open my $fh, '<', $filepath
        or croak "Cannot open plugin for scanning: $filepath: $!";
    my $code = do { local $/; <$fh> };
    close $fh;

    # List of dangerous patterns that plugins should not use
    my @forbidden_patterns = (
        qr/\beval\s*\(/,                    # No nested eval
        qr/\beval\s*\{/,                    # No eval blocks with dynamic code
        qr/\bsystem\s*[\(\s]/,              # No system calls
        qr/\bexec\s*[\(\s]/,                # No exec
        qr/\b`[^`]*`/,                      # No backticks
        qr/\bqx\s*[\{\(\[\/]/,              # No qx
        qr/\bopen\s*\(\s*\$?\w+\s*,\s*["']\s*\|/,  # No pipe opens
        qr/\|\s*["']\s*\)/,                 # No output pipe opens
        qr/\brequire\s/,                    # No require
        qr/\buse\s+(?!strict|warnings|Carp)/, # Only allow safe modules
        qr/\bBEGIN\s*\{/,                   # No BEGIN blocks
        qr/\bEND\s*\{/,                     # No END blocks
        qr/\bINIT\s*\{/,                    # No INIT blocks
        qr/\bCHECK\s*\{/,                   # No CHECK blocks
        qr/\bUNITCHECK\s*\{/,              # No UNITCHECK blocks
        qr/\bDESTROY\s/,                    # No DESTROY methods
        qr/\bAUTOLOAD\b/,                   # No AUTOLOAD
        qr/\bunlink\s/,                      # No file deletion
        qr/\bchmod\s/,                       # No permission changes
        qr/\bchown\s/,                       # No ownership changes
        qr/\brename\s/,                      # No file renaming
        qr/\bsymlink\s/,                     # No symlink creation
        qr/\bfork\s*\(/,                    # No forking
        qr/\bsocket\s*\(/,                  # No socket operations
        qr/\bconnect\s*\(/,                 # No network connections
        qr/\bbind\s*\(/,                    # No binding
        qr/\blisten\s*\(/,                  # No listening
        qr/\baccept\s*\(/,                  # No accepting connections
        qr/\bglob\s*[\(\s]/,               # No glob
        qr/\bdo\s+["']/,                    # No do FILE
    );

    for my $pattern (@forbidden_patterns) {
        if ($code =~ $pattern) {
            croak "Plugin contains forbidden pattern ($pattern) in: $filepath";
        }
    }

    return 1;
}

# =============================================================================
# Load and execute a plugin safely in a restricted namespace
# =============================================================================
sub load_plugin {
    my ($plugin_name, $context) = @_;

    # Step 1: Validate plugin name
    validate_plugin_name($plugin_name);

    # Step 2: Validate directory permissions
    validate_directory_permissions($PLUGIN_DIR);

    # Step 3: Load and check manifest
    my $manifest = load_manifest($MANIFEST_FILE);

    unless (exists $manifest->{$plugin_name}) {
        croak "Plugin '$plugin_name' is not registered in the manifest";
    }

    # Step 4: Build full path and validate file
    my $plugin_path = "$PLUGIN_DIR/$plugin_name";

    # Resolve and verify the path doesn't escape the plugin directory
    use Cwd qw(abs_path);
    my $abs_plugin_dir  = abs_path($PLUGIN_DIR);
    my $abs_plugin_path = abs_path($plugin_path);

    unless (defined $abs_plugin_path && $abs_plugin_path =~ /^\Q$abs_plugin_dir\E\//) {
        croak "Plugin path escapes plugin directory (possible path traversal): $plugin_name";
    }

    validate_file_permissions($abs_plugin_path);

    # Step 5: Verify checksum
    verify_checksum($abs_plugin_path, $manifest->{$plugin_name});

    # Step 6: Scan for dangerous code patterns
    scan_plugin_code($abs_plugin_path);

    # Step 7: Load plugin in a sandboxed namespace using 'do' (not eval on string)
    my $namespace = "PluginSandbox::$plugin_name";
    $namespace =~ s/\.pl$//;
    $namespace =~ s/[^a-zA-Z0-9_]/_/g;

    # Create a wrapper that loads the plugin into a restricted namespace
    my $result;
    {
        # Use 'do' to load the file - this is safer than eval($string)
        # because the code comes from a verified file, not a string
        package main;

        local $@;
        $result = do $abs_plugin_path;

        if ($@) {
            croak "Plugin '$plugin_name' compilation error: $@";
        }
        if (!defined $result && $!) {
            croak "Plugin '$plugin_name' could not be read: $!";
        }
    }

    return $result;
}

# =============================================================================
# Execute a loaded plugin's 'run' function
# =============================================================================
sub execute_plugin {
    my ($plugin_name, %params) = @_;

    print "--- Loading plugin: $plugin_name ---\n";

    # Load the plugin (all security checks happen here)
    my $plugin_result = load_plugin($plugin_name, \%params);

    # The plugin should return a hash ref with a 'run' code ref
    unless (ref $plugin_result eq 'HASH' && ref $plugin_result->{run} eq 'CODE') {
        croak "Plugin '$plugin_name' must return a hashref with a 'run' code reference";
    }

    # Execute the plugin's run function with provided parameters
    print "--- Executing plugin: $plugin_name ---\n";
    my $output;
    local $@;
    eval {
        # Use alarm for timeout protection
        local $SIG{ALRM} = sub { die "Plugin execution timed out\n" };
        alarm(10);  # 10 second timeout

        $output = $plugin_result->{run}->(%params);

        alarm(0);
    };
    alarm(0);  # Ensure alarm is cleared

    if ($@) {
        croak "Plugin '$plugin_name' runtime error: $@";
    }

    print "--- Plugin '$plugin_name' completed successfully ---\n";
    return $output;
}

# =============================================================================
# Utility: Generate manifest entry for a plugin file
# =============================================================================
sub generate_manifest_entry {
    my ($filepath) = @_;

    open my $fh, '<', $filepath
        or croak "Cannot open file: $filepath: $!";
    my $content = do { local $/; <$fh> };
    close $fh;

    my $checksum = sha256_hex($content);
    my $name     = basename($filepath);

    return "$checksum  $name";
}

